#![allow(non_snake_case)]

use std::sync::Arc;

use anyhow::{bail, Result};
use arcstr::ArcStr;

use metamodelica::ext::{c_atof, c_atol};
use metamodelica::{list, List, OrderedFloat, Real};

/// Cost coefficients (m, n) for one arithmetic operation: `y = m*x + n`.
/// Upstream `HpcOmBenchmarkExtImpl__requiredTimeForOp` returns the hardcoded
/// pair (1, 24) — the original RDTSC micro-benchmark is commented out there
/// ("the values are bad for equation systems", see `HpcOmBenchmark.benchSystem`).
pub fn requiredTimeForOp() -> Result<Arc<List<i32>>> {
    Ok(list![1, 24])
}

/// Cost coefficients (m, n) for communicating x doubles to another CPU:
/// `y = m*x + n`. Upstream returns the hardcoded pair (4, 70).
pub fn requiredTimeForComm() -> Result<Arc<List<i32>>> {
    Ok(list![4, 70])
}

/// Prepend one profiled block's (id, time, count) onto the result list,
/// mirroring the three `mmc_mk_cons` pushes per block in the C++ readers
/// (the resulting head order count, time, id is what
/// `HpcOmBenchmark.expandCalcTimes` destructures).
fn push_block(acc: Arc<List<Real>>, id: f64, time: f64, count: f64) -> Arc<List<Real>> {
    let acc = metamodelica::cons(OrderedFloat(id), acc);
    let acc = metamodelica::cons(OrderedFloat(time), acc);
    metamodelica::cons(OrderedFloat(count), acc)
}

/// Reads the per-equation calculation times from a `<prefix>_prof.xml`
/// profiling file (deprecated upstream in favour of the .json file).
///
/// Expected document shape (see `printEquations` in
/// `SimulationRuntime/c/simulation/modelinfo.c`):
///
/// ```xml
/// <simulation>           <!-- depth 1 -->
///   <modelinfo>...</modelinfo>
///   ...
///   <equations>          <!-- depth 2 -->
///     <equation id="eq7">          <!-- depth 3; id written as "eq%d" -->
///       <refs>...</refs>
///       <calcinfo time="0.000012" count="101"/>   <!-- depth 4 -->
///     </equation>
///   </equations>
/// </simulation>
/// ```
///
/// Like the expat handler upstream, only `<equation>` elements at depth 3 and
/// the *first* `<calcinfo>` at depth 4 below each are considered, and the id
/// is parsed by skipping the first two characters ("eq") of the attribute.
///
/// Divergence from C++: on a missing file the C++ returns a list containing
/// an error *string* (ill-typed as `list<Real>`; its consumer would fail when
/// reading it) — here the print is kept and the function fails directly. On a
/// malformed document expat returns the blocks parsed before the error, while
/// roxmltree parses the whole document up front, so we return an empty list.
/// Neither case occurs with runtime-written files.
pub fn readCalcTimesFromXml(fileName: ArcStr) -> Result<Arc<List<Real>>> {
    let Ok(content) = std::fs::read_to_string(fileName.as_str()) else {
        // Mirrors the printf in HpcOmBenchmarkExtImpl__readCalcTimesFromXml.
        println!("File '{}' does not exist", fileName);
        bail!("File '{}' does not exist", fileName);
    };
    let mut res: Arc<List<Real>> = metamodelica::nil();
    let doc = match roxmltree::Document::parse(&content) {
        Ok(doc) => doc,
        Err(_) => return Ok(res), // C++: stop parsing, keep what was read so far
    };
    // root_element() is depth 1, its element children depth 2, etc.
    for level2 in doc.root_element().children().filter(|n| n.is_element()) {
        for equation in level2.children().filter(|n| n.is_element() && n.has_tag_name("equation")) {
            let Some(id_attr) = equation.attribute("id") else { continue };
            // strtol(id + 2): skip the fixed "eq" prefix the runtime writes.
            let id = if id_attr.len() >= 2 { c_atol(&id_attr[2..]) } else { 0 };
            // Only the first <calcinfo> counts (upstream clears
            // currentEquation after handling it).
            if let Some(calcinfo) = equation
                .children()
                .find(|n| n.is_element() && n.has_tag_name("calcinfo"))
            {
                let time = calcinfo.attribute("time").map_or(-1.0, c_atof);
                let count = calcinfo
                    .attribute("count")
                    .map_or(-1.0, |v| c_atol(v) as f64);
                res = push_block(res, id as f64, time, count);
            }
        }
    }
    Ok(res)
}

/// Reads the per-block calculation times from a `<prefix>_prof.json`
/// profiling file: the `profileBlocks` array of
/// `{"id": <int>, "ncall": <int>, "time": <real>, "maxTime": <real>}`
/// objects (see `printJSONProfileBlocks` in
/// `SimulationRuntime/c/simulation/modelinfo.c`).
///
/// Divergence from C++: on a missing file the C++ returns a list containing
/// an error *string* (ill-typed as `list<Real>`) — here the print is kept and
/// the function fails directly. Malformed JSON / missing `profileBlocks` keep
/// the upstream behaviour: a message on stderr and an empty result.
pub fn readCalcTimesFromJson(fileName: ArcStr) -> Result<Arc<List<Real>>> {
    let Ok(content) = std::fs::read(fileName.as_str()) else {
        // Mirrors the printf in HpcOmBenchmarkExtImpl__readCalcTimesFromJson.
        println!("File '{}' does not exist", fileName);
        bail!("File '{}' does not exist", fileName);
    };
    let mut res: Arc<List<Real>> = metamodelica::nil();
    let Ok(root) = serde_json::from_slice::<serde_json::Value>(&content) else {
        eprintln!("no root object defined in json-file - maybe the json file is corrupt");
        return Ok(res);
    };
    let Some(blocks) = root.get("profileBlocks").and_then(|v| v.as_array()) else {
        eprintln!("no profile blocks defined in json-file");
        return Ok(res);
    };
    for item in blocks {
        // cJSON: a string id goes through atof; anything else is read as a
        // double (0.0 for non-numbers, matching cJSON's valuedouble default).
        let id = match item.get("id") {
            Some(serde_json::Value::String(s)) => c_atof(s),
            Some(v) => v.as_f64().unwrap_or(0.0),
            None => 0.0,
        };
        let time = item.get("time").and_then(|v| v.as_f64()).unwrap_or(0.0);
        let ncall = item.get("ncall").and_then(|v| v.as_f64()).unwrap_or(0.0);
        res = push_block(res, id, time, ncall);
    }
    Ok(res)
}

#[cfg(test)]
mod tests {
    use super::*;

    fn to_vec(lst: Arc<List<Real>>) -> Vec<f64> {
        (&*lst).into_iter().map(|r| r.0).collect()
    }

    #[test]
    fn required_times_match_upstream_constants() {
        let op: Vec<i32> = (&*requiredTimeForOp().unwrap()).into_iter().copied().collect();
        assert_eq!(op, vec![1, 24]);
        let comm: Vec<i32> = (&*requiredTimeForComm().unwrap()).into_iter().copied().collect();
        assert_eq!(comm, vec![4, 70]);
    }

    #[test]
    fn c_numeric_prefix_parsers() {
        assert_eq!(c_atof("0.000012\""), 0.000012);
        assert_eq!(c_atof("1.5e3x"), 1500.0);
        assert_eq!(c_atof("junk"), 0.0);
        assert_eq!(c_atol("101abc"), 101);
        assert_eq!(c_atol("-7"), -7);
        assert_eq!(c_atol(""), 0);
    }

    #[test]
    fn xml_blocks_are_prepended_in_document_order() {
        let dir = std::env::temp_dir().join("hpcom_bench_xml_test");
        std::fs::create_dir_all(&dir).unwrap();
        let path = dir.join("model_prof.xml");
        std::fs::write(
            &path,
            r#"<simulation>
  <equations>
    <equation id="eq3">
      <refs><ref refid="var0" /></refs>
      <calcinfo time="0.25" count="10"/>
    </equation>
    <equation id="eq4">
      <calcinfo time="0.5" count="20"/>
    </equation>
    <equation id="eq5"><refs/></equation>
  </equations>
</simulation>"#,
        )
        .unwrap();
        let got = to_vec(readCalcTimesFromXml(path.to_str().unwrap().into()).unwrap());
        // Last block first; per block: count, time, id. eq5 has no calcinfo
        // and is skipped, like upstream.
        assert_eq!(got, vec![20.0, 0.5, 4.0, 10.0, 0.25, 3.0]);
        std::fs::remove_file(&path).unwrap();
    }

    #[test]
    fn json_blocks_are_prepended_in_document_order() {
        let dir = std::env::temp_dir().join("hpcom_bench_json_test");
        std::fs::create_dir_all(&dir).unwrap();
        let path = dir.join("model_prof.json");
        std::fs::write(
            &path,
            r#"{"name":"M","profileBlocks":[
                {"id":12,"ncall":5,"time":0.125,"maxTime":0.5},
                {"id":13,"ncall":6,"time":0.250,"maxTime":0.5}
            ]}"#,
        )
        .unwrap();
        let got = to_vec(readCalcTimesFromJson(path.to_str().unwrap().into()).unwrap());
        assert_eq!(got, vec![6.0, 0.25, 13.0, 5.0, 0.125, 12.0]);
        std::fs::remove_file(&path).unwrap();
    }

    #[test]
    fn missing_file_fails() {
        assert!(readCalcTimesFromXml("/nonexistent/x_prof.xml".into()).is_err());
        assert!(readCalcTimesFromJson("/nonexistent/x_prof.json".into()).is_err());
    }
}
